// Generate timestamp ONCE at the top
const dt = $now.setZone('Asia/Jerusalem');
const folderName = `PI workflows backup ${dt.toFormat('yyyy-MM-dd HH-mm')}`;
const timestamp = dt.toFormat('yyyy-MM-dd HH:mm');

return $items().map((item) => {
  const json = item.json || {};
  const bin  = item.binary || {};
  const data = bin.data || {};

  const orig = (data.fileName || (json.name ? json.name + '.json' : 'workflow.json')).toString();

  const safe = orig
    .replace(/[\/\\]+/g, '-')
    .replace(/\s+/g, ' ')
    .trim();

  bin.data = Object.assign({}, data, { fileName: safe });

  json.workflowName = json.name || safe.replace('.json', '');
  json.folderName = folderName;      // ✅ Store for GitHub Backup
  json.timestamp = timestamp;        // ✅ Store for README

  return { json, binary: bin };
});

const text = ($json.readme || '# PI workflows backup\n\n(empty)')
  .replace(/\r?\n/g, '\n');

const getReadmeItem = $item(0, 'GitHub Get README');
const sha = getReadmeItem?.json?.sha || '';

return {
  json: { sha },
  binary: {
    data: {
      data: Buffer.from(text, 'utf8').toString('base64'),
      fileName: 'README.md',
      mimeType: 'text/markdown'
    }
  }
};

// Get the stored timestamp from Normalize Filename1
const normalizeItems = $items('Normalize Filename1') || [];
const storedData = normalizeItems[0]?.json || {};

const folder = storedData.folderName;
const timestamp = storedData.timestamp;

// Collect workflow names
let workflowNames = normalizeItems
  .map(item => item.json?.workflowName)
  .filter(name => name);

// GitHub backup info
const OWNER = "alexxx55555";
const REPO  = "n8n-Raspberry-PI-Workflow-Backup";
const BRANCH = "main";

const ghUrl = `https://github.com/${OWNER}/${encodeURIComponent(REPO)}/tree/${encodeURIComponent(BRANCH)}/${encodeURIComponent(folder)}`;

// Markdown README content
const readme = `# n8n-Raspberry-PI-Workflow-Backup

## Latest Backup: ${timestamp}

### Backup URL
${ghUrl}

### Workflows Backed Up (${workflowNames.length} total)
${workflowNames.length ? workflowNames.map(n => `- ${n}`).join("\n") : "- (no workflows found)"}

---
*Backup generated automatically by n8n*`;

return [{
  json: {
    readme,
    timestamp,
    folder,
    ghUrl,
    workflowCount: workflowNames.length
  }
}];

// Collect all workflow names that were just backed up
const normalizeItems = $items('Normalize Filename1') || [];
const workflowNames = normalizeItems
  .map(item => item.json?.workflowName || item.binary?.data?.fileName || 'Unknown Workflow')
  .filter(name => name && name !== 'Unknown Workflow');

// Pass the names to the next node
return [{ json: { backedUpWorkflows: workflowNames } }];

const name = $json.name || 'workflow-backup';
const filename = name + '.json';
const fileContent = JSON.stringify($json, null, 2);

return {
  json: { name: name },
  binary: {
    data: {
      data: Buffer.from(fileContent).toString('base64'),
      mimeType: 'application/json',
      fileName: filename
    }
  }
};

// The current items are from GitHub List (no folderName)
// But the LAST item passed into this node still has context from the backup
// So we need to find folderName from the folder names themselves

// Get all dirs that match our pattern
const folders = $items().filter(i =>
  i.json &&
  i.json.type === "dir" &&
  typeof i.json.name === "string" &&
  i.json.name.startsWith("PI workflows backup ")
);

// Sort descending by name (date-based names sort correctly as strings)
const sorted = [...folders].sort((a, b) => b.json.name.localeCompare(a.json.name));

// The newest folder is first — keep it, delete the rest
const newest = sorted[0]?.json?.name;

if (!newest) return [];

return sorted
  .slice(1)  // everything except the newest
  .map(i => ({ json: { path: i.json.path, name: i.json.name } }));

